SELECT Item.[trademark code], Item.[season code], Item_1.[Line Code], [Item Cross Reference].[Cross-Reference No_], Item_1.No_ AS Model, Item_1.[Description 2], LettureTXT.EANCODELETTORETXT AS EAN, Item.[Variable Code 01] AS Color, Item.[Variable Code 02] AS [Size], "" AS [Location Code], Sum(1) AS paia, Sum(1) AS paialIBERE
FROM (LettureTXT LEFT JOIN BarCodes_CleanDoubled ON LettureTXT.EANCODELETTORETXT = BarCodes_CleanDoubled.[Cross-Reference No_]) LEFT JOIN (([Item Cross Reference] LEFT JOIN Item ON [Item Cross Reference].[Item No_] = Item.No_) LEFT JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) ON (BarCodes_CleanDoubled.[MaxDiItem No_] = [Item Cross Reference].[Item No_]) AND (BarCodes_CleanDoubled.[Cross-Reference No_] = [Item Cross Reference].[Cross-Reference No_])
GROUP BY Item.[trademark code], Item.[season code], Item_1.[Line Code], [Item Cross Reference].[Cross-Reference No_], Item_1.No_, Item_1.[Description 2], LettureTXT.EANCODELETTORETXT, Item.[Variable Code 01], Item.[Variable Code 02], "";

